#include <gtest/gtest.h>
#include "solvers/subsetFinder.h"

TEST(TestHiddenPair,HiddenPair1){
    //1,9 in r15c8 => r15c8<>8.in
    Inst inst = {0x34,0x07,0x00,0x47,0x08,0x07,0x07,0x47,0x07};
    std::vector<uint16_t> executees = {0x0707,0x4707};
    Grid grid("");
    findHiddenSubset(grid, 2);
    EXPECT_EQ(grid.instructions, inst);
    EXPECT_EQ(grid.execution.mode,false);
    EXPECT_EQ(grid.execution.executees,executees);
}

TEST(TestHiddenPair,HiddenPair2){
    //4,9 in r1c25 => r1c2<>5, r1c2<>6, r1c25<>8.in
    Inst inst = {0x34,0x01,0x03,0x04,0x08,0x01,0x04,0x01,0x05,0x01,0x07,0x04,0x07};
    std::vector<uint16_t> executees = {0x0104,0x0105,0x0107,0x0407};
    Grid grid("");
    findHiddenSubset(grid, 2);
    EXPECT_EQ(grid.instructions, inst);
    EXPECT_EQ(grid.execution.mode,false);
    EXPECT_EQ(grid.execution.executees,executees);
}

TEST(TestNakedPair,NakedPair1){
    //1,5 in r4c3,r5c2 => r6c23<>1.in
    Inst inst = {0x30,0x32,0x00,0x41,0x04,0x51,0x00,0x52,0x00};
    std::vector<uint16_t> executees = {0x5100,0x5200};
    Grid grid("");
    findNakedSubset(grid, 2);
    EXPECT_EQ(grid.instructions, inst);
    EXPECT_EQ(grid.execution.mode,false);
    EXPECT_EQ(grid.execution.executees,executees);
}

TEST(TestNakedPair,NakedPair2){
    //Naked Pair: 1,6 in r34c6 => r1c6<>6, r89c6<>1
    Inst inst = {0x30,0x25,0x00,0x35,0x05,0x05,0x05,0x75,0x00,0x85,0x00};
    std::vector<uint16_t> executees = {0x1505,0x7500,0x8500};
    Grid grid("");
    findNakedSubset(grid, 2);
    EXPECT_EQ(grid.instructions, inst);
    EXPECT_EQ(grid.execution.mode,false);
    EXPECT_EQ(grid.execution.executees,executees);
}